+/**
+ * Audit logging service — records every notification dispatched through the system.
+ *
+ * Subscribes to `notification:requested` events on the EventBus and keeps
+ * a timestamped log of all dispatched notifications for compliance and debugging.
+ */
+
+import type { EventBus } from '../events/event-bus.js';
+import type { NotificationRequestedEvent, NotificationPriority } from '../events/event-types.js';
+
+export interface AuditLogEntry {
+  id: string;
+  channel: string;
+  priority: NotificationPriority;
+  recipient: string;
+  subject: string;
+  timestamp: Date;
+  recordedAt: Date;
+}
+
+let nextAuditId = 1;
+
+function generateAuditId(): string {
+  return `audit-${String(nextAuditId++).padStart(4, '0')}`;
+}
+
+export function resetAuditIdCounter(): void {
+  nextAuditId = 1;
+}
+
+export class AuditService {
+  private entries: AuditLogEntry[] = [];
+
+  constructor(private eventBus: EventBus) {
+    this.eventBus.on<NotificationRequestedEvent>('notification:requested', (event) => {
+      this.record(event);
+    });
+  }
+
+  private record(event: NotificationRequestedEvent): void {
+    this.entries.push({
+      id: generateAuditId(),
+      channel: event.channel,
+      priority: event.priority,
+      recipient: event.recipient,
+      subject: event.subject,
+      timestamp: event.timestamp,
+      recordedAt: new Date(),
+    });
+  }
+
+  getEntries(): AuditLogEntry[] {
+    return [...this.entries];
+  }
+
+  getEntriesByRecipient(recipient: string): AuditLogEntry[] {
+    return this.entries.filter((e) => e.recipient === recipient);
+  }
+
+  getEntriesByChannel(channel: string): AuditLogEntry[] {
+    return this.entries.filter((e) => e.channel === channel);
+  }
+
+  getEntryCount(): number {
+    return this.entries.length;
+  }
+
+  clear(): void {
+    this.entries = [];
+  }
+}

