+/**
+ * Notification preferences service — allows per-user channel overrides.
+ *
+ * When a user has a preferred channel set, it overrides the default
+ * priority-based routing from the PriorityRouter. If no preference
+ * is set, the priority router's default channel is used.
+ */
+
+import type { NotificationPriority } from '../events/event-types.js';
+import { PriorityRouter } from './priority-router.js';
+
+export type NotificationChannel = 'email' | 'sms' | 'webhook';
+
+export interface UserChannelPreference {
+  userId: string;
+  channel: NotificationChannel;
+}
+
+export class NotificationPreferencesService {
+  private preferences: Map<string, NotificationChannel> = new Map();
+  private router = new PriorityRouter();
+
+  setPreference(userId: string, channel: NotificationChannel): void {
+    this.preferences.set(userId, channel);
+  }
+
+  getPreference(userId: string): NotificationChannel | undefined {
+    return this.preferences.get(userId);
+  }
+
+  removePreference(userId: string): boolean {
+    return this.preferences.delete(userId);
+  }
+
+  /**
+   * Resolve the channel for a notification. If the user has a preference,
+   * use it; otherwise fall back to priority-based routing.
+   */
+  resolveChannel(userId: string, priority: NotificationPriority): string {
+    const preference = this.preferences.get(userId);
+    if (preference) {
+      return preference;
+    }
+    return this.router.route(priority);
+  }
+
+  clear(): void {
+    this.preferences.clear();
+  }
+}

