/**
 * Audit logging service — records every notification dispatched through the system.
 *
 * Subscribes to `notification:requested` events on the EventBus and keeps
 * a timestamped log of all dispatched notifications for compliance and debugging.
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationRequestedEvent, NotificationPriority } from '../events/event-types.js';

export interface AuditLogEntry {
  id: string;
  channel: string;
  priority: NotificationPriority;
  recipient: string;
  subject: string;
  timestamp: Date;
  recordedAt: Date;
}

let nextAuditId = 1;

function generateAuditId(): string {
  return `audit-${String(nextAuditId++).padStart(4, '0')}`;
}

export function resetAuditIdCounter(): void {
  nextAuditId = 1;
}

export class AuditService {
  private entries: AuditLogEntry[] = [];

  constructor(private eventBus: EventBus) {
    this.eventBus.on<NotificationRequestedEvent>('notification:requested', (event) => {
      this.record(event);
    });
  }

  private record(event: NotificationRequestedEvent): void {
    this.entries.push({
      id: generateAuditId(),
      channel: event.channel,
      priority: event.priority,
      recipient: event.recipient,
      subject: event.subject,
      timestamp: event.timestamp,
      recordedAt: new Date(),
    });
  }

  getEntries(): AuditLogEntry[] {
    return [...this.entries];
  }

  getEntriesByRecipient(recipient: string): AuditLogEntry[] {
    return this.entries.filter((e) => e.recipient === recipient);
  }

  getEntriesByChannel(channel: string): AuditLogEntry[] {
    return this.entries.filter((e) => e.channel === channel);
  }

  getEntryCount(): number {
    return this.entries.length;
  }

  clear(): void {
    this.entries = [];
  }
}

/**
 * Notification preferences service — allows per-user channel overrides.
 *
 * When a user has a preferred channel set, it overrides the default
 * priority-based routing from the PriorityRouter. If no preference
 * is set, the priority router's default channel is used.
 */

import type { NotificationPriority } from '../events/event-types.js';
import { PriorityRouter } from './priority-router.js';

export type NotificationChannel = 'email' | 'sms' | 'webhook';

export interface UserChannelPreference {
  userId: string;
  channel: NotificationChannel;
}

export class NotificationPreferencesService {
  private preferences: Map<string, NotificationChannel> = new Map();
  private router = new PriorityRouter();

  setPreference(userId: string, channel: NotificationChannel): void {
    this.preferences.set(userId, channel);
  }

  getPreference(userId: string): NotificationChannel | undefined {
    return this.preferences.get(userId);
  }

  removePreference(userId: string): boolean {
    return this.preferences.delete(userId);
  }

  /**
   * Resolve the channel for a notification. If the user has a preference,
   * use it; otherwise fall back to priority-based routing.
   */
  resolveChannel(userId: string, priority: NotificationPriority): string {
    const preference = this.preferences.get(userId);
    if (preference) {
      return preference;
    }
    return this.router.route(priority);
  }

  clear(): void {
    this.preferences.clear();
  }
}

